// lib/payment/security/payment_security.dart
import 'dart:convert';
import 'dart:math';
import 'dart:typed_data';
import 'package:crypto/crypto.dart';
import 'package:encrypt/encrypt.dart' as encrypt_lib;
import 'package:flutter_secure_storage/flutter_secure_storage.dart';

class PaymentSecurityService {
  static const _secureStorage = FlutterSecureStorage(
    aOptions: AndroidOptions(encryptedSharedPreferences: true),
    iOptions: IOSOptions(
      accessibility: KeychainAccessibility.first_unlock_this_device,
    ),
  );

  static const String _encryptionKeyAlias = 'payment_enc_key';
  static const String _tokenPrefix = 'tok_';

  Future<void> initialize() async {
    final existingKey = await _secureStorage.read(key: _encryptionKeyAlias);
    if (existingKey == null) {
      final key = _generateSecureKey(32);
      await _secureStorage.write(key: _encryptionKeyAlias, value: key);
    }
  }

  String _generateSecureKey(int length) {
    final random = Random.secure();
    final values = List<int>.generate(length, (i) => random.nextInt(256));
    return base64Url.encode(values);
  }

  Future<String> encryptSensitiveData(String data) async {
    final keyString = await _secureStorage.read(key: _encryptionKeyAlias);
    if (keyString == null) throw PaymentSecurityException('Encryption key not found');

    final key = encrypt_lib.Key.fromBase64(keyString);
    final iv = encrypt_lib.IV.fromSecureRandom(16);
    final encrypter = encrypt_lib.Encrypter(encrypt_lib.AES(key, mode: encrypt_lib.AESMode.cbc));

    final encrypted = encrypter.encrypt(data, iv: iv);
    return '${iv.base64}:${encrypted.base64}';
  }

  Future<String> decryptSensitiveData(String encryptedData) async {
    final keyString = await _secureStorage.read(key: _encryptionKeyAlias);
    if (keyString == null) throw PaymentSecurityException('Encryption key not found');

    final parts = encryptedData.split(':');
    if (parts.length != 2) throw PaymentSecurityException('Invalid encrypted data format');

    final key = encrypt_lib.Key.fromBase64(keyString);
    final iv = encrypt_lib.IV.fromBase64(parts[0]);
    final encrypter = encrypt_lib.Encrypter(encrypt_lib.AES(key, mode: encrypt_lib.AESMode.cbc));

    return encrypter.decrypt64(parts[1], iv: iv);
  }

  Future<void> storeToken(String tokenId, String tokenValue) async {
    final encrypted = await encryptSensitiveData(tokenValue);
    await _secureStorage.write(key: '$_tokenPrefix$tokenId', value: encrypted);
  }

  Future<String?> retrieveToken(String tokenId) async {
    final encrypted = await _secureStorage.read(key: '$_tokenPrefix$tokenId');
    if (encrypted == null) return null;
    return decryptSensitiveData(encrypted);
  }

  Future<void> deleteToken(String tokenId) async {
    await _secureStorage.delete(key: '$_tokenPrefix$tokenId');
  }

  Future<void> clearAllTokens() async {
    await _secureStorage.deleteAll();
    await initialize();
  }

  String hashForIntegrity(String data) {
    final bytes = utf8.encode(data);
    final digest = sha256.convert(bytes);
    return digest.toString();
  }

  bool verifyIntegrity(String data, String expectedHash) {
    return hashForIntegrity(data) == expectedHash;
  }

  String sanitizeCardNumber(String cardNumber) {
    return cardNumber.replaceAll(RegExp(r'\D'), '');
  }

  String maskCardNumber(String cardNumber) {
    final sanitized = sanitizeCardNumber(cardNumber);
    if (sanitized.length < 4) return '****';
    return '**** **** **** ${sanitized.substring(sanitized.length - 4)}';
  }

  bool validateCardNumber(String cardNumber) {
    final sanitized = sanitizeCardNumber(cardNumber);
    if (sanitized.length < 13 || sanitized.length > 19) return false;
    return _luhnCheck(sanitized);
  }

  bool _luhnCheck(String number) {
    int sum = 0;
    bool alternate = false;
    for (int i = number.length - 1; i >= 0; i--) {
      int digit = int.parse(number[i]);
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      sum += digit;
      alternate = !alternate;
    }
    return sum % 10 == 0;
  }

  bool validateExpiry(int month, int year) {
    if (month < 1 || month > 12) return false;
    final now = DateTime.now();
    final expiry = DateTime(year, month + 1, 0);
    return expiry.isAfter(now);
  }

  bool validateCVV(String cvv) {
    return RegExp(r'^\d{3,4}$').hasMatch(cvv);
  }

  String generateIdempotencyKey() {
    final random = Random.secure();
    final values = List<int>.generate(16, (i) => random.nextInt(256));
    return base64Url.encode(values).replaceAll('=', '');
  }
}

class PaymentSecurityException implements Exception {
  final String message;
  PaymentSecurityException(this.message);

  @override
  String toString() => 'PaymentSecurityException: $message';
}

