// lib/payment/api/payment_api_client.dart
import 'dart:convert';
import 'dart:io';
import 'package:http/http.dart' as http;

class PaymentApiClient {
  final PaymentConfig config;
  final PaymentSecurityService security;
  final http.Client _httpClient;

  PaymentApiClient({
    required this.config,
    required this.security,
    http.Client? httpClient,
  }) : _httpClient = httpClient ?? http.Client();

  Map<String, String> get _headers => {
        'Content-Type': 'application/json',
        'Accept': 'application/json',
        'X-Api-Version': '2024-01',
        'X-Idempotency-Key': security.generateIdempotencyKey(),
      };

  Future<Map<String, String>> _authenticatedHeaders(String? authToken) async {
    final headers = Map<String, String>.from(_headers);
    if (authToken != null) {
      headers['Authorization'] = 'Bearer $authToken';
    }
    return headers;
  }

  Future<PaymentIntent> createPaymentIntent({
    required int amount,
    required String currency,
    required PaymentMethod method,
    String? customerId,
    String? authToken,
    Map<String, dynamic>? metadata,
  }) async {
    final headers = await _authenticatedHeaders(authToken);
    final body = jsonEncode({
      'amount': amount,
      'currency': currency,
      'payment_method_type': method.name,
      'customer_id': customerId,
      'metadata': metadata,
    });

    final response = await _httpClient
        .post(
          Uri.parse('${config.backendBaseUrl}/api/payments/intent'),
          headers: headers,
          body: body,
        )
        .timeout(Duration(seconds: config.transactionTimeoutSeconds));

    if (response.statusCode == 200 || response.statusCode == 201) {
      return PaymentIntent.fromJson(jsonDecode(response.body));
    }

    throw PaymentApiException(
      statusCode: response.statusCode,
      message: _parseErrorMessage(response.body),
    );
  }

  Future<PaymentResult> confirmPayment({
    required String paymentIntentId,
    required String paymentMethodId,
    String? authToken,
  }) async {
    final headers = await _authenticatedHeaders(authToken);
    final body = jsonEncode({
      'payment_intent_id': paymentIntentId,
      'payment_method_id': paymentMethodId,
    });

    final response = await _httpClient
        .post(
          Uri.parse('${config.backendBaseUrl}/api/payments/confirm'),
          headers: headers,
          body: body,
        )
        .timeout(Duration(seconds: config.transactionTimeoutSeconds));

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      return PaymentResult.succeeded(TransactionRecord.fromJson(data['transaction']));
    }

    final errorData = jsonDecode(response.body);
    return PaymentResult.failed(
      errorData['error_code'] ?? 'unknown_error',
      errorData['error_message'] ?? 'Payment confirmation failed',
    );
  }

  Future<TransactionRecord> verifyReceipt({
    required String receiptData,
    required String productId,
    required String platform,
    String? authToken,
  }) async {
    final headers = await _authenticatedHeaders(authToken);
    final body = jsonEncode({
      'receipt_data': receiptData,
      'product_id': productId,
      'platform': platform,
    });

    final response = await _httpClient
        .post(
          Uri.parse('${config.backendBaseUrl}/api/payments/verify-receipt'),
          headers: headers,
          body: body,
        )
        .timeout(Duration(seconds: config.transactionTimeoutSeconds));

    if (response.statusCode == 200) {
      return TransactionRecord.fromJson(jsonDecode(response.body));
    }

    throw PaymentApiException(
      statusCode: response.statusCode,
      message: _parseErrorMessage(response.body),
    );
  }

  Future<List<TransactionRecord>> getTransactionHistory({
    String? authToken,
    int page = 1,
    int limit = 20,
  }) async {
    final headers = await _authenticatedHeaders(authToken);

    final response = await _httpClient
        .get(
          Uri.parse(
              '${config.backendBaseUrl}/api/payments/transactions?page=$page&limit=$limit'),
          headers: headers,
        )
        .timeout(Duration(seconds: config.transactionTimeoutSeconds));

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body) as List;
      return data.map((e) => TransactionRecord.fromJson(e)).toList();
    }

    throw PaymentApiException(
      statusCode: response.statusCode,
      message: _parseErrorMessage(response.body),
    );
  }

  Future<PaymentResult> requestRefund({
    required String transactionId,
    int? amount,
    String? reason,
    String? authToken,
  }) async {
    final headers = await _authenticatedHeaders(authToken);
    final body = jsonEncode({
      'transaction_id': transactionId,
      'amount': amount,
      'reason': reason,
    });

    final response = await _httpClient
        .post(
          Uri.parse('${config.backendBaseUrl}/api/payments/refund'),
          headers: headers,
          body: body,
        )
        .timeout(Duration(seconds: config.transactionTimeoutSeconds));

    if (response.statusCode == 200) {
      final data = jsonDecode(response.body);
      return PaymentResult.succeeded(TransactionRecord.fromJson(data['transaction']));
    }

    final errorData = jsonDecode(response.body);
    return PaymentResult.failed(
      errorData['error_code'] ?? 'refund_failed',
      errorData['error_message'] ?? 'Refund request failed',
    );
  }

  String _parseErrorMessage(String body) {
    try {
      final data = jsonDecode(body);
      return data['message'] ?? data['error'] ?? 'Unknown error';
    } catch (_) {
      return 'Unknown error occurred';
    }
  }

  void dispose() {
    _httpClient.close();
  }
}

class PaymentApiException implements Exception {
  final int statusCode;
  final String message;

  PaymentApiException({required this.statusCode, required this.message});

  @override
  String toString() => 'PaymentApiException($statusCode): $message';
}

