// lib/payment/gateways/stripe_gateway.dart
import 'package:flutter_stripe/flutter_stripe.dart' as stripe;

class StripeGatewayService {
  final PaymentConfig config;
  final PaymentApiClient apiClient;
  final PaymentSecurityService security;

  StripeGatewayService({
    required this.config,
    required this.apiClient,
    required this.security,
  });

  Future<void> initialize() async {
    stripe.Stripe.publishableKey = config.stripePublishableKey;
    stripe.Stripe.merchantIdentifier = config.merchantId;
    stripe.Stripe.urlScheme = 'flutterpayment';
    await stripe.Stripe.instance.applySettings();
  }

  Future<PaymentResult> processCardPayment({
    required int amount,
    required String currency,
    String? customerId,
    String? authToken,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      // 1. Create payment intent on backend
      final paymentIntent = await apiClient.createPaymentIntent(
        amount: amount,
        currency: currency,
        method: PaymentMethod.creditCard,
        customerId: customerId,
        authToken: authToken,
        metadata: metadata,
      );

      // 2. Initialize payment sheet
      await stripe.Stripe.instance.initPaymentSheet(
        paymentSheetParameters: stripe.SetupPaymentSheetParameters(
          paymentIntentClientSecret: paymentIntent.clientSecret,
          merchantDisplayName: config.merchantName,
          customerId: customerId,
          style: stripe.ThemeMode.system,
          appearance: const stripe.PaymentSheetAppearance(
            colors: stripe.PaymentSheetAppearanceColors(
              primary: Color(0xFF6750A4),
            ),
            shapes: stripe.PaymentSheetShape(
              borderRadius: 12,
            ),
          ),
        ),
      );

      // 3. Present payment sheet
      await stripe.Stripe.instance.presentPaymentSheet();

      // 4. Confirm payment on backend
      return await apiClient.confirmPayment(
        paymentIntentId: paymentIntent.id,
        paymentMethodId: 'stripe_sheet',
        authToken: authToken,
      );
    } on stripe.StripeException catch (e) {
      if (e.error.code == stripe.FailureCode.Canceled) {
        return PaymentResult.failed('payment_cancelled', 'Payment was cancelled by user');
      }
      return PaymentResult.failed(
        'stripe_error',
        e.error.localizedMessage ?? 'Payment failed',
      );
    } catch (e) {
      return PaymentResult.failed('payment_error', e.toString());
    }
  }

  Future<PaymentResult> processApplePay({
    required int amount,
    required String currency,
    required String label,
    String? customerId,
    String? authToken,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      final isSupported = await stripe.Stripe.instance.isApplePaySupported();
      if (!isSupported) {
        return PaymentResult.failed('not_supported', 'Apple Pay is not available on this device');
      }

      final paymentIntent = await apiClient.createPaymentIntent(
        amount: amount,
        currency: currency,
        method: PaymentMethod.applePay,
        customerId: customerId,
        authToken: authToken,
        metadata: metadata,
      );

      await stripe.Stripe.instance.presentApplePay(
        params: stripe.ApplePayPresentParams(
          cartItems: [
            stripe.ApplePayCartSummaryItem.immediate(
              label: label,
              amount: (amount / 100).toStringAsFixed(2),
            ),
          ],
          country: 'US',
          currency: currency,
        ),
      );

      await stripe.Stripe.instance.confirmApplePayPayment(
        paymentIntent.clientSecret,
      );

      return await apiClient.confirmPayment(
        paymentIntentId: paymentIntent.id,
        paymentMethodId: 'apple_pay',
        authToken: authToken,
      );
    } on stripe.StripeException catch (e) {
      if (e.error.code == stripe.FailureCode.Canceled) {
        return PaymentResult.failed('payment_cancelled', 'Apple Pay was cancelled');
      }
      return PaymentResult.failed('apple_pay_error', e.error.localizedMessage ?? 'Apple Pay failed');
    } catch (e) {
      return PaymentResult.failed('apple_pay_error', e.toString());
    }
  }

  Future<PaymentResult> processGooglePay({
    required int amount,
    required String currency,
    required String label,
    String? customerId,
    String? authToken,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      final isSupported = await stripe.Stripe.instance.isGooglePaySupported(
        const stripe.IsGooglePaySupportedParams(),
      );
      if (!isSupported) {
        return PaymentResult.failed('not_supported', 'Google Pay is not available on this device');
      }

      final paymentIntent = await apiClient.createPaymentIntent(
        amount: amount,
        currency: currency,
        method: PaymentMethod.googlePay,
        customerId: customerId,
        authToken: authToken,
        metadata: metadata,
      );

      await stripe.Stripe.instance.initGooglePay(
        stripe.GooglePayInitParams(
          merchantName: config.merchantName,
          countryCode: 'US',
          testEnv: !config.isProduction,
        ),
      );

      await stripe.Stripe.instance.presentGooglePay(
        stripe.PresentGooglePayParams(
          clientSecret: paymentIntent.clientSecret,
        ),
      );

      return await apiClient.confirmPayment(
        paymentIntentId: paymentIntent.id,
        paymentMethodId: 'google_pay',
        authToken: authToken,
      );
    } on stripe.StripeException catch (e) {
      if (e.error.code == stripe.FailureCode.Canceled) {
        return PaymentResult.failed('payment_cancelled', 'Google Pay was cancelled');
      }
      return PaymentResult.failed('google_pay_error', e.error.localizedMessage ?? 'Google Pay failed');
    } catch (e) {
      return PaymentResult.failed('google_pay_error', e.toString());
    }
  }
}

