// lib/payment/iap/in_app_purchase_service.dart
import 'dart:async';
import 'dart:io';
import 'package:in_app_purchase/in_app_purchase.dart';
import 'package:in_app_purchase_storekit/in_app_purchase_storekit.dart';
import 'package:in_app_purchase_android/in_app_purchase_android.dart';

class InAppPurchaseService {
  final PaymentApiClient apiClient;
  final PaymentSecurityService security;

  final InAppPurchase _iap = InAppPurchase.instance;
  StreamSubscription<List<PurchaseDetails>>? _subscription;

  final _purchaseController = StreamController<PurchaseUpdate>.broadcast();
  Stream<PurchaseUpdate> get purchaseStream => _purchaseController.stream;

  final Map<String, InAppProduct> _products = {};
  List<InAppProduct> get availableProducts => _products.values.toList();

  bool _isAvailable = false;
  bool get isAvailable => _isAvailable;

  InAppPurchaseService({
    required this.apiClient,
    required this.security,
  });

  Future<void> initialize(Set<String> productIds) async {
    _isAvailable = await _iap.isAvailable();
    if (!_isAvailable) return;

    // Configure platform-specific options
    if (Platform.isIOS) {
      final iosPlatformAddition =
          _iap.getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await iosPlatformAddition.setDelegate(ExamplePaymentQueueDelegate());
    }

    // Listen to purchase updates
    _subscription = _iap.purchaseStream.listen(
      _handlePurchaseUpdates,
      onDone: () => _subscription?.cancel(),
      onError: (error) {
        _purchaseController.add(PurchaseUpdate(
          status: PurchaseUpdateStatus.error,
          errorMessage: error.toString(),
        ));
      },
    );

    // Load products
    await loadProducts(productIds);
  }

  Future<void> loadProducts(Set<String> productIds) async {
    final response = await _iap.queryProductDetails(productIds);

    if (response.error != null) {
      _purchaseController.add(PurchaseUpdate(
        status: PurchaseUpdateStatus.error,
        errorMessage: 'Failed to load products: ${response.error!.message}',
      ));
      return;
    }

    _products.clear();
    for (final product in response.productDetails) {
      _products[product.id] = InAppProduct(
        productId: product.id,
        title: product.title,
        description: product.description,
        price: product.price,
        rawPrice: product.rawPrice,
        currencyCode: product.currencyCode,
        type: _determineProductType(product),
      );
    }

    if (response.notFoundIDs.isNotEmpty) {
      _purchaseController.add(PurchaseUpdate(
        status: PurchaseUpdateStatus.productsNotFound,
        errorMessage: 'Products not found: ${response.notFoundIDs.join(", ")}',
      ));
    }
  }

  ProductType _determineProductType(ProductDetails product) {
    // Determine based on product ID naming convention or platform-specific data
    if (product.id.contains('subscription')) return ProductType.subscription;
    if (product.id.contains('consumable')) return ProductType.consumable;
    return ProductType.nonConsumable;
  }

  Future<bool> purchaseProduct(String productId, {String? authToken}) async {
    if (!_isAvailable) return false;

    final product = _products[productId];
    if (product == null) return false;

    final productDetails = (await _iap.queryProductDetails({productId}))
        .productDetails
        .firstOrNull;

    if (productDetails == null) return false;

    final purchaseParam = PurchaseParam(
      productDetails: productDetails,
      applicationUserName: security.generateIdempotencyKey(),
    );

    if (product.type == ProductType.consumable) {
      return await _iap.buyConsumable(purchaseParam: purchaseParam);
    } else {
      return await _iap.buyNonConsumable(purchaseParam: purchaseParam);
    }
  }

  Future<void> _handlePurchaseUpdates(List<PurchaseDetails> purchases) async {
    for (final purchase in purchases) {
      switch (purchase.status) {
        case PurchaseStatus.pending:
          _purchaseController.add(PurchaseUpdate(
            status: PurchaseUpdateStatus.pending,
            productId: purchase.productID,
          ));
          break;

        case PurchaseStatus.purchased:
        case PurchaseStatus.restored:
          final verified = await _verifyAndDeliverPurchase(purchase);
          if (verified) {
            _purchaseController.add(PurchaseUpdate(
              status: PurchaseUpdateStatus.completed,
              productId: purchase.productID,
              transactionId: purchase.purchaseID,
            ));
          } else {
            _purchaseController.add(PurchaseUpdate(
              status: PurchaseUpdateStatus.verificationFailed,
              productId: purchase.productID,
              errorMessage: 'Server-side verification failed',
            ));
          }
          break;

        case PurchaseStatus.error:
          _purchaseController.add(PurchaseUpdate(
            status: PurchaseUpdateStatus.error,
            productId: purchase.productID,
            errorMessage: purchase.error?.message ?? 'Purchase failed',
          ));
          break;

        case PurchaseStatus.canceled:
          _purchaseController.add(PurchaseUpdate(
            status: PurchaseUpdateStatus.cancelled,
            productId: purchase.productID,
          ));
          break;
      }

      if (purchase.pendingCompletePurchase) {
        await _iap.completePurchase(purchase);
      }
    }
  }

  Future<bool> _verifyAndDeliverPurchase(PurchaseDetails purchase) async {
    try {
      String receiptData;
      String platform;

      if (Platform.isIOS) {
        receiptData = purchase.verificationData.serverVerificationData;
        platform = 'ios';
      } else {
        receiptData = purchase.verificationData.serverVerificationData;
        platform = 'android';
      }

      await apiClient.verifyReceipt(
        receiptData: receiptData,
        productId: purchase.productID,
        platform: platform,
      );

      return true;
    } catch (e) {
      return false;
    }
  }

  Future<void> restorePurchases() async {
    if (!_isAvailable) return;
    await _iap.restorePurchases();
  }

  void dispose() {
    _subscription?.cancel();
    _purchaseController.close();
  }
}

class PurchaseUpdate {
  final PurchaseUpdateStatus status;
  final String? productId;
  final String? transactionId;
  final String? errorMessage;

  PurchaseUpdate({
    required this.status,
    this.productId,
    this.transactionId,
    this.errorMessage,
  });
}

enum PurchaseUpdateStatus {
  pending,
  completed,
  cancelled,
  error,
  verificationFailed,
  productsNotFound,
}

