// lib/payment/payment_service.dart
import 'dart:async';

class PaymentService {
  final PaymentConfig config;
  late final PaymentSecurityService _security;
  late final PaymentApiClient _apiClient;
  late final StripeGatewayService _stripeGateway;
  late final InAppPurchaseService _iapService;

  bool _initialized = false;

  final _transactionLog = <TransactionRecord>[];
  List<TransactionRecord> get transactionHistory => List.unmodifiable(_transactionLog);

  final _stateController = StreamController<PaymentServiceState>.broadcast();
  Stream<PaymentServiceState> get stateStream => _stateController.stream;

  PaymentService({required this.config});

  Future<void> initialize({Set<String>? iapProductIds}) async {
    if (_initialized) return;

    _security = PaymentSecurityService();
    await _security.initialize();

    _apiClient = PaymentApiClient(config: config, security: _security);

    _stripeGateway = StripeGatewayService(
      config: config,
      apiClient: _apiClient,
      security: _security,
    );
    await _stripeGateway.initialize();

    _iapService = InAppPurchaseService(
      apiClient: _apiClient,
      security: _security,
    );

    if (iapProductIds != null && iapProductIds.isNotEmpty) {
      await _iapService.initialize(iapProductIds);
    }

    _initialized = true;
    _stateController.add(PaymentServiceState.ready);
  }

  void _ensureInitialized() {
    if (!_initialized) {
      throw StateError('PaymentService not initialized. Call initialize() first.');
    }
  }

  // Credit Card Payment
  Future<PaymentResult> payWithCard({
    required int amountInCents,
    required String currency,
    String? customerId,
    String? authToken,
    Map<String, dynamic>? metadata,
  }) async {
    _ensureInitialized();
    _stateController.add(PaymentServiceState.processing);

    try {
      final result = await _stripeGateway.processCardPayment(
        amount: amountInCents,
        currency: currency,
        customerId: customerId,
        authToken: authToken,
        metadata: metadata,
      );

      if (result.transaction != null) {
        _transactionLog.add(result.transaction!);
      }

      _stateController.add(
        result.success ? PaymentServiceState.ready : PaymentServiceState.error,
      );

      return result;
    } catch (e) {
      _stateController.add(PaymentServiceState.error);
      return PaymentResult.failed('unexpected_error', e.toString());
    }
  }

  // Apple Pay
  Future<PaymentResult> payWithApplePay({
    required int amountInCents,
    required String currency,
    required String itemLabel,
    String? customerId,
    String? authToken,
    Map<String, dynamic>? metadata,
  }) async {
    _ensureInitialized();
    _stateController.add(PaymentServiceState.processing);

    try {
      final result = await _stripeGateway.processApplePay(
        amount: amountInCents,
        currency: currency,
        label: itemLabel,
        customerId: customerId,
        authToken: authToken,
        metadata: metadata,
      );

      if (result.transaction != null) {
        _transactionLog.add(result.transaction!);
      }

      _stateController.add(
        result.success ? PaymentServiceState.ready : PaymentServiceState.error,
      );

      return result;
    } catch (e) {
      _stateController.add(PaymentServiceState.error);
      return PaymentResult.failed('unexpected_error', e.toString());
    }
  }

  // Google Pay
  Future<PaymentResult> payWithGooglePay({
    required int amountInCents,
    required String currency,
    required String itemLabel,
    String? customerId,
    String? authToken,
    Map<String, dynamic>? metadata,
  }) async {
    _ensureInitialized();
    _stateController.add(PaymentServiceState.processing);

    try {
      final result = await _stripeGateway.processGooglePay(
        amount: amountInCents,
        currency: currency,
        label: itemLabel,
        customerId: customerId,
        authToken: authToken,
        metadata: metadata,
      );

      if (result.transaction != null) {
        _transactionLog.add(result.transaction!);
      }

      _stateController.add(
        result.success ? PaymentServiceState.ready : PaymentServiceState.error,
      );

      return result;
    } catch (e) {
      _stateController.add(PaymentServiceState.error);
      return PaymentResult.failed('unexpected_error', e.toString());
    }
  }

  // In-App Purchase
  Future<bool> purchaseInApp(String productId) async {
    _ensureInitialized();
    _stateController.add(PaymentServiceState.processing);

    final result = await _iapService.purchaseProduct(productId);

    if (!result) {
      _stateController.add(PaymentServiceState.error);
    }

    return result;
  }

  // Restore purchases
  Future<void> restorePurchases() async {
    _ensureInitialized();
    await _iapService.restorePurchases();
  }

  // Get available IAP products
  List<InAppProduct> get availableProducts => _iapService.availableProducts;
  bool get isIAPAvailable => _iapService.isAvailable;

  // IAP purchase stream
  Stream<PurchaseUpdate> get purchaseUpdates => _iapService.purchaseStream;

  // Refund
  Future<PaymentResult> requestRefund({
    required String transactionId,
    int? amountInCents,
    String? reason,
    String? authToken,
  }) async {
    _ensureInitialized();

    return await _apiClient.requestRefund(
      transactionId: transactionId,
      amount: amountInCents,
      reason: reason,
      authToken: authToken,
    );
  }

  // Transaction history from backend
  Future<List<TransactionRecord>> fetchTransactionHistory({
    String? authToken,
    int page = 1,
    int limit = 20,
  }) async {
    _ensureInitialized();
    return await _apiClient.getTransactionHistory(
      authToken: authToken,
      page: page,
      limit: limit,
    );
  }

  // Security
  PaymentSecurityService get securityService => _security;

  void dispose() {
    _iapService.dispose();
    _apiClient.dispose();
    _stateController.close();
  }
}

enum PaymentServiceState { uninitialized, ready, processing, error }

