// lib/payment/bloc/payment_bloc.dart
import 'dart:async';
import 'package:flutter_bloc/flutter_bloc.dart';
import 'package:equatable/equatable.dart';

// Events
abstract class PaymentEvent extends Equatable {
  const PaymentEvent();

  @override
  List<Object?> get props => [];
}

class InitializePayment extends PaymentEvent {}

class ProcessCardPayment extends PaymentEvent {
  final int amountInCents;
  final String currency;
  final String? customerId;
  final Map<String, dynamic>? metadata;

  const ProcessCardPayment({
    required this.amountInCents,
    required this.currency,
    this.customerId,
    this.metadata,
  });

  @override
  List<Object?> get props => [amountInCents, currency, customerId, metadata];
}

class ProcessApplePayPayment extends PaymentEvent {
  final int amountInCents;
  final String currency;
  final String itemLabel;

  const ProcessApplePayPayment({
    required this.amountInCents,
    required this.currency,
    required this.itemLabel,
  });

  @override
  List<Object?> get props => [amountInCents, currency, itemLabel];
}

class ProcessGooglePayPayment extends PaymentEvent {
  final int amountInCents;
  final String currency;
  final String itemLabel;

  const ProcessGooglePayPayment({
    required this.amountInCents,
    required this.currency,
    required this.itemLabel,
  });

  @override
  List<Object?> get props => [amountInCents, currency, itemLabel];
}

class PurchaseInAppProduct extends PaymentEvent {
  final String productId;

  const PurchaseInAppProduct({required this.productId});

  @override
  List<Object?> get props => [productId];
}

class RestoreInAppPurchases extends PaymentEvent {}

class LoadTransactionHistory extends PaymentEvent {
  final int page;
  final int limit;

  const LoadTransactionHistory({this.page = 1, this.limit = 20});

  @override
  List<Object?> get props => [page, limit];
}

class RequestRefund extends PaymentEvent {
  final String transactionId;
  final int? amountInCents;
  final String? reason;

  const RequestRefund({
    required this.transactionId,
    this.amountInCents,
    this.reason,
  });

  @override
  List<Object?> get props => [transactionId, amountInCents, reason];
}

// States
abstract class PaymentState extends Equatable {
  const PaymentState();

  @override
  List<Object?> get props => [];
}

class PaymentInitial extends PaymentState {}

class PaymentLoading extends PaymentState {
  final String message;

  const PaymentLoading({this.message = 'Processing...'});

  @override
  List<Object?> get props => [message];
}

class PaymentReady extends PaymentState {
  final List<InAppProduct> availableProducts;

  const PaymentReady({this.availableProducts = const []});

  @override
  List<Object?> get props => [availableProducts];
}

class PaymentSuccess extends PaymentState {
  final PaymentResult result;

  const PaymentSuccess({required this.result});

  @override
  List<Object?> get props => [result];
}

class PaymentFailure extends PaymentState {
  final String errorCode;
  final String errorMessage;

  const PaymentFailure({required this.errorCode, required this.errorMessage});

  @override
  List<Object?> get props => [errorCode, errorMessage];
}

class TransactionHistoryLoaded extends PaymentState {
  final List<TransactionRecord> transactions;

  const TransactionHistoryLoaded({required this.transactions});

  @override
  List<Object?> get props => [transactions];
}

class InAppPurchaseUpdated extends PaymentState {
  final PurchaseUpdate update;

  const InAppPurchaseUpdated({required this.update});

  @override
  List<Object?> get props => [update];
}

// Bloc
class PaymentBloc extends Bloc<PaymentEvent, PaymentState> {
  final PaymentService paymentService;
  final String? authToken;
  StreamSubscription<PurchaseUpdate>? _purchaseSubscription;

  PaymentBloc({
    required this.paymentService,
    this.authToken,
  }) : super(PaymentInitial()) {
    on<InitializePayment>(_onInitialize);
    on<ProcessCardPayment>(_onProcessCardPayment);
    on<ProcessApplePayPayment>(_onProcessApplePay);
    on<ProcessGooglePayPayment>(_onProcessGooglePay);
    on<PurchaseInAppProduct>(_onPurchaseInApp);
    on<RestoreInAppPurchases>(_onRestorePurchases);
    on<LoadTransactionHistory>(_onLoadHistory);
    on<RequestRefund>(_onRequestRefund);
  }

  Future<void> _onInitialize(
    InitializePayment event,
    Emitter<PaymentState> emit,
  ) async {
    emit(const PaymentLoading(message: 'Initializing payment system...'));

    try {
      await paymentService.initialize(
        iapProductIds: {'premium_monthly', 'premium_yearly', 'coins_100'},
      );

      _purchaseSubscription = paymentService.purchaseUpdates.listen(
        (update) => add(_IAPUpdateReceived(update: update)),
      );

      emit(PaymentReady(availableProducts: paymentService.availableProducts));
    } catch (e) {
      emit(PaymentFailure(errorCode: 'init_failed', errorMessage: e.toString()));
    }
  }

  Future<void> _onProcessCardPayment(
    ProcessCardPayment event,
    Emitter<PaymentState> emit,
  ) async {
    emit(const PaymentLoading(message: 'Processing card payment...'));

    final result = await paymentService.payWithCard(
      amountInCents: event.amountInCents,
      currency: event.currency,
      customerId: event.customerId,
      authToken: authToken,
      metadata: event.metadata,
    );

    if (result.success) {
      emit(PaymentSuccess(result: result));
    } else {
      emit(PaymentFailure(
        errorCode: result.errorCode ?? 'unknown',
        errorMessage: result.errorMessage ?? 'Payment failed',
      ));
    }
  }

  Future<void> _onProcessApplePay(
    ProcessApplePayPayment event,
    Emitter<PaymentState> emit,
  ) async {
    emit(const PaymentLoading(message: 'Processing Apple Pay...'));

    final result = await paymentService.payWithApplePay(
      amountInCents: event.amountInCents,
      currency: event.currency,
      itemLabel: event.itemLabel,
      authToken: authToken,
    );

    if (result.success) {
      emit(PaymentSuccess(result: result));
    } else {
      emit(PaymentFailure(
        errorCode: result.errorCode ?? 'unknown',
        errorMessage: result.errorMessage ?? 'Apple Pay failed',
      ));
    }
  }

  Future<void> _onProcessGooglePay(
    ProcessGooglePayPayment event,
    Emitter<PaymentState> emit,
  ) async {
    emit(const PaymentLoading(message: 'Processing Google Pay...'));

    final result = await paymentService.payWithGooglePay(
      amountInCents: event.amountInCents,
      currency: event.currency,
      itemLabel: event.itemLabel,
      authToken: authToken,
    );

    if (result.success) {
      emit(PaymentSuccess(result: result));
    } else {
      emit(PaymentFailure(
        errorCode: result.errorCode ?? 'unknown',
        errorMessage: result.errorMessage ?? 'Google Pay failed',
      ));
    }
  }

  Future<void> _onPurchaseInApp(
    PurchaseInAppProduct event,
    Emitter<PaymentState> emit,
  ) async {
    emit(const PaymentLoading(message: 'Processing in-app purchase...'));

    final success = await paymentService.purchaseInApp(event.productId);
    if (!success) {
      emit(const PaymentFailure(
        errorCode: 'iap_failed',
        errorMessage: 'Failed to initiate in-app purchase',
      ));
    }
    // Further updates come through the purchase stream
  }

  Future<void> _onRestorePurchases(
    RestoreInAppPurchases event,
    Emitter<PaymentState> emit,
  ) async {
    emit(const PaymentLoading(message: 'Restoring purchases...'));
    await paymentService.restorePurchases();
  }

  Future<void> _onLoadHistory(
    LoadTransactionHistory event,
    Emitter<PaymentState> emit,
  ) async {
    emit(const PaymentLoading(message: 'Loading transactions...'));

    try {
      final transactions = await paymentService.fetchTransactionHistory(
        authToken: authToken,
        page: event.page,
        limit: event.limit,
      );
      emit(TransactionHistoryLoaded(transactions: transactions));
    } catch (e) {
      emit(PaymentFailure(
        errorCode: 'history_failed',
        errorMessage: e.toString(),
      ));
    }
  }

  Future<void> _onRequestRefund(
    RequestRefund event,
    Emitter<PaymentState> emit,
  ) async {
    emit(const PaymentLoading(message: 'Processing refund...'));

    final result = await paymentService.requestRefund(
      transactionId: event.transactionId,
      amountInCents: event.amountInCents,
      reason: event.reason,
      authToken: authToken,
    );

    if (result.success) {
      emit(PaymentSuccess(result: result));
    } else {
      emit(PaymentFailure(
        errorCode: result.errorCode ?? 'refund_failed',
        errorMessage: result.errorMessage ?? 'Refund failed',
      ));
    }
  }

  @override
  Future<void> close() {
    _purchaseSubscription?.cancel();
    return super.close();
  }
}

// Internal event for IAP stream updates
class _IAPUpdateReceived extends PaymentEvent {
  final PurchaseUpdate update;
  const _IAPUpdateReceived({required this.update});
}

